arguments.file_text:
namespace sv_95cade61cb2f4469b1a1fcd7f112b7b3.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);

public record Message(
    int Id,
    int ChannelId,
    string Author,
    string Content,
    DateTime SentAt,
    int? ReplyToId,
    List<Reaction> Reactions);

public record Reaction(string Emoji, List<string> Users);

public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_95cade61cb2f4469b1a1fcd7f112b7b3.Models

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelected.InvokeAsync(Channel)">
    <div class="channel-item-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "..." : desc;
}

.channel-item {
    padding: 6px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-item-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-size: 0.95rem;
    font-weight: 500;
    color: #d1d2d3;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.channel-item.active .channel-name,
.channel-item:hover .channel-name {
    color: #ffffff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8e9297;
    margin-top: 1px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

@using sv_95cade61cb2f4469b1a1fcd7f112b7b3.Models

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Messaging</h5>
    </div>
    <div class="sidebar-section-label">Channels</div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="ActiveChannelId == channel.Id"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 260px;
    min-width: 260px;
    background-color: #1a1d21;
    color: #d1d2d3;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #2c2f33;
    overflow: hidden;
}

.sidebar-header {
    padding: 14px 16px 8px;
    border-bottom: 1px solid #2c2f33;
}

.sidebar-header h5 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
