{"path": "/tmp/sv-95cade61cb2f4469b1a1fcd7f112b7b3/Components/Pages/Chat/ChatPage.razor", "file_text": "@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_95cade61cb2f4469b1a1fcd7f112b7b3.Models

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannel?.Id"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area">
        @if (activeChannel is not null)
        {
            <div class="channel-header">
                <div class="channel-header-name"># @activeChannel.Name</div>
                <div class="channel-header-desc">@activeChannel.Description</div>
            </div>

            <div class="message-list">
                @if (hasMoreMessages)
                {
                    <button class="load-more-btn" @onclick="LoadMoreMessages" disabled="@isLoadingMore">
                        @(isLoadingMore ? "Loading..." : "⬆ Load older messages")
                    </button>
                }
                @foreach (var msg in displayMessages)
                {
                    <MessageItem Message="msg"
                                 ReplyCount="GetReplyCount(msg.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="HandleReaction" />
                }
                @if (!displayMessages.Any())
                {
                    <div class="empty-state">No messages yet. Start the conversation!</div>
                }
            </div>

            <MessageInput Placeholder="@($"Message #{activeChannel.Name}")"
                          ButtonText="Send"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="empty-state center">Select a channel to start chatting</div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendReply"
                     OnReact="HandleReaction" />
    }
</div>

@code {
    [Inject] private IChatService ChatService { get; set; } = default!;

    private List<Channel> channels = new();
    private Channel? activeChannel;
    private List<Message> allMessages = new();
    private Dictionary<int, int> replyCounts = new();
    private int skip;
    private const int PageSize = 50;
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    // Show only root-level messages in the main feed
    private IEnumerable<Message> displayMessages
        => allMessages.Where(m => m.ReplyToId is null);

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        activeChannel = channel;
        skip = 0;
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = new();

        allMessages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        hasMoreMessages = allMessages.Count >= PageSize;
        ComputeReplyCounts();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh the channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (activeChannel is null || isLoadingMore || !hasMoreMessages) return;
        isLoadingMore = true;
        skip += PageSize;
        var older = await ChatService.GetMessagesAsync(activeChannel.Id, skip, PageSize);
        hasMoreMessages = older.Count >= PageSize;
        allMessages.InsertRange(0, older);
        ComputeReplyCounts();
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var msg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        allMessages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = allMessages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
    }

    private async Task SendReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        allMessages.Add(reply);
        ComputeReplyCounts();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic UI update in both main and thread message lists
        UpdateReactionOnMessage(allMessages, args.MessageId, args.Emoji);
        UpdateReactionOnMessage(threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionOnMessage(List<Message> messages, int messageId, string emoji)
    {
        var msg = messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return;
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
            existing.Users.Add("You");
        else
            msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
    }

    private int GetReplyCount(int messageId)
        => replyCounts.GetValueOrDefault(messageId);

    private void ComputeReplyCounts()
    {
        replyCounts = allMessages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}
"}

