toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1d1c1d;
}

.message-time {
    font-size: 0.75rem;
    color: #616061;
}

.message-body {
    font-size: 0.9rem;
    color: #1d1c1d;
    line-height: 1.5;
    word-wrap: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background-color: #f0f4f8;
    border: 1px solid #d1d5da;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #dce6f0;
    border-color: #1264a3;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.hover-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background-color: #ffffff;
    border: 1px solid #d1d5da;
    border-radius: 8px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.12);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 6px;
    color: #616061;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background-color: #f0f4f8;
    color: #1d1c1d;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background-color: #ffffff;
    border: 1px solid #d1d5da;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    margin-top: 4px;
    width: fit-content;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    cursor: pointer;
    border-radius: 6px;
    transition: background-color 0.15s;
}

.emoji-option:hover {
    background-color: #f0f4f8;
}

