toolArgs.file_text:
@using sv_95cade61cb2f4469b1a1fcd7f112b7b3.Models

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Reply..." ButtonText="Reply" OnSend="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    // No-op for nested thread opening; keeps MessageItem's parameter satisfied
    private EventCallback<int> OnOpenThread => EventCallback.Factory.Create<int>(this, _ => { });
}

.thread-panel {
    width: 380px;
    min-width: 380px;
    background-color: #ffffff;
    border-left: 1px solid #e1e4e8;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e1e4e8;
}

.thread-header h6 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #1d1c1d;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    color: #616061;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 6px;
    transition: background-color 0.15s;
}

.close-btn:hover {
    background-color: #f0f4f8;
    color: #1d1c1d;
}

.thread-root-quote {
    margin: 12px 16px;
    padding: 10px 12px;
    background-color: #f8f8f8;
    border-left: 3px solid #1264a3;
    border-radius: 0 6px 6px 0;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #1d1c1d;
}

.quote-content {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #616061;
    line-height: 1.4;
}

.thread-divider {
    display: flex;
    align-items: center;
    padding: 0 16px;
    margin: 4px 0;
}

.thread-divider::before,
.thread-divider::after {
    content: "";
    flex: 1;
    border-bottom: 1px solid #e1e4e8;
}

.thread-divider span {
    padding: 0 10px;
    font-size: 0.75rem;
    color: #616061;
    white-space: nowrap;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

