toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background-color: #f8f8f8;
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background-color: #ffffff;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

.channel-header-name {
    font-size: 1.1rem;
    font-weight: 700;
    color: #1d1c1d;
}

.channel-header-desc {
    font-size: 0.8rem;
    color: #616061;
    margin-top: 2px;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.load-more-btn {
    display: block;
    margin: 8px auto;
    background: none;
    border: 1px solid #d1d5da;
    border-radius: 20px;
    padding: 6px 16px;
    font-size: 0.8rem;
    color: #1264a3;
    cursor: pointer;
    transition: background-color 0.15s;
}

.load-more-btn:hover:not(:disabled) {
    background-color: #f0f4f8;
}

.load-more-btn:disabled {
    color: #8e9297;
    cursor: not-allowed;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 40px 20px;
    color: #616061;
    font-size: 0.95rem;
}

.empty-state.center {
    flex: 1;
}

