+.load-more-btn {
+    display: block;
+    margin: 8px auto;
+    background: none;
+    border: 1px solid #d1d5da;
+    border-radius: 20px;
+    padding: 6px 16px;
+    font-size: 0.8rem;
+    color: #1264a3;
+    cursor: pointer;
+    transition: background-color 0.15s;
+}
+
+.load-more-btn:hover:not(:disabled) {
+    background-color: #f0f4f8;
+}
+
+.load-more-btn:disabled {
+    color: #8e9297;
+    cursor: not-allowed;
+}
+
+.empty-state {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    padding: 40px 20px;
+    color: #616061;
+    font-size: 0.95rem;
+}
+
+.empty-state.center {
+    flex: 1;
+}
